Hi Kimura-san!

I think I figured it out.

Could you please compile following program on problematic system:

=======================
/* rlnkat2.c */

#include <sys/stat.h>

#include <errno.h>
#include <fcntl.h>
#include <unistd.h>
#include <stdio.h>
#include <string.h>
#include <strings.h>

#define BUFSIZE 1024

int
main(int argc, char** argv)
{
  int i,ret;
  char buffer[BUFSIZE];
  struct stat st;
  int fd;

  for(i = 1; i < argc; i++) {
    bzero( buffer, sizeof( buffer ));
    fd = AT_FDCWD;
    ret = EINVAL;
#ifdef O_PATH
    fprintf( stderr, "Trying openat(%s): ", argv[i]);
    ret = openat( fd, argv[i], O_PATH | O_CLOEXEC | O_NOFOLLOW, 0);
    if( -1 == ret ) {
      ret = errno;
      perror("openat");
    } else {
      fprintf( stderr, "%d\n", ret );
      if( 0 != fstat( ret, &st )) {
	ret = errno;
	fprintf( stderr, "fstat(%s): errno: %d, %s\n", argv[i], errno, strerror(errno)); 
      } else {
	fd = ret;
	ret = 0;
      };
    }
#endif
    if( EINVAL == ret ) {
      ret = fstatat( fd, argv[i], &st, AT_SYMLINK_NOFOLLOW );
    }
    if( -1 == ret ) {
      perror("fstatat");
      continue;
    }
    if( S_ISLNK( st.st_mode )) {
      ret = readlinkat( fd, argv[i], buffer, sizeof( buffer ));
      if( -1 == ret ) {
	perror("readlinkat");
      } else {
	fprintf(stderr, "%d. %s symlink to %s\n", i, argv[i], buffer );
      }
    } else {
      fprintf( stderr, "%d. %s (is directory: %d)\n", i, argv[i], S_ISDIR( st.st_mode));
    }
  }
  return 0;
}
=================



% cc -o rlnkat rlnkat.c

% ./rlnkat .emacs .init-files/.emacs .init-files

My guess is O_PATH is defined in 14-CURRENT[0], which enables openat(), which is passed a symlink as parameter with O_NOFOLLOW.

========== excerpt from open(2): 
     [EMLINK]           O_NOFOLLOW was specified and the target is a symbolic
                        link.
==========

So the culprit is openat but it only gets enabled/compiled on a system which has O_PATH defined in its headers (which only happened after that particular revision[0]).

If this is indeed the case, then as per man page of open(2)[1] from GNU/Linux:

=========
       ELOOP  Too many symbolic links were encountered in resolving pathname.

       ELOOP  pathname was a symbolic link, and flags specified O_NOFOLLOW but not O_PATH.
=========

it seems like a bug in FreeBSD implement, as GNU Emacs seems to be passing O_PATH along with O_NOFOLLOW which should not cause this EMLINK error.

Anyways, this is all a speculation, so please let us know the output. And thank you for trying various things. 

References:

[0] https://cgit.freebsd.org/src/commit/?id=8d9ed174f3afba5f114742447e622fc1173d4774

[1] https://www.man7.org/linux/man-pages/man2/open.2.html

Good night!
